/*
 * Return the product of the vector x with every odd indexed element inverted.
 * i.e. x_0 * 1/x_1 * x_2 * 1/x_3 * x_4 ...
 * Example:
 * input: [4, 2, 10, 4, 5]
 * output: 25
 */
inline double productWithInverses(const std::vector<double>& x) {
    double result = 1.0;
    const size_t n = x.size();

    /* parallel exclusive reduction with OpenMP 4.0+
     * using a custom reduction on product */
#pragma omp parallel for reduction(+:result) default(none) shared(x, n)
    for (size_t i = 0; i < n; ++i) {
        double v = (i & 1) ? 1.0 / x[i] : x[i];
        result *= v;
    }
    return result;
