   A is an NxN adjacency matrix stored in row‑major order.
   Return the maximum row sum.
*/
int maxDegree(const std::vector<int>& A, size_t N) {
    int max_degs = 0;

    // Parallel over rows; use reduction to track the maximum degree.
    #pragma omp parallel for reduction(max:max_degs) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        int deg = 0;
        // Load pointer to the start of the i-th row to avoid repeated multiplication.
        const int* row = &A[i * N];
        for (size_t j = 0; j < N; ++j) {
            deg += row[j];
        }
        if (deg > max_degs) max_degs = deg;  // Optional: same as reduction
    }

    return max_degs;
}
