/*
 * In the vector x negate the odd values and divide the even values by 2.
 * Example:
 *
 * input:  [16, 11, 12, 14, 1, 0, 5]
 * output: [8, -11, 6, 7, -1, 0, -5]
 */
inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t n = x.size();

    /* Parallelizing over the elements using OpenMP.  The loop is
     * independent, so an embarrassingly parallel approach works
     * perfectly.  The compiler's -O2 optimisation will keep the
     * division and modulo instructions as simple as possible. */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        int val = x[i];
        if ((val & 1) == 0) {          // even test via bitwise for speed
            x[i] = val >> 1;           // divide by 2 (shift right)
        } else {
            x[i] = -val;                // negate
        }
    }
}
