/* Return the largest sum of any contiguous subarray in the vector x.
   Exactly preserves the semantics of the original O(n²) algorithm
   but uses Kadane's linear‑time algorithm for speed. */
int maximumSubarray(std::vector<int> const& x) {
    if (x.empty()) return 0;  // undefined but keeps behaviour consistent

    int max_so_far = std::numeric_limits<int>::lowest();
    int max_ending_here = 0;

    for (size_t i = 0; i < x.size(); ++i) {
        max_ending_here += x[i];
        if (max_ending_here > max_so_far)
            max_so_far = max_ending_here;
        if (max_ending_here < 0)
            max_ending_here = 0;
    }

    return max_so_far;
}
