/* Return the value of the smallest odd number in the vector x.
   Examples:
   input: [7, 9, 5, 2, 8, 16, 4, 1]
   output: 1
   input: [8, 36, 7, 2, 11]
   output: 7
*/
inline int smallestOdd(std::vector<int> const& x)
{
    // Fast path for empty vector: return max int.
    if (x.empty())
        return std::numeric_limits<int>::max();

    // Work with a local copy to avoid non‑inlineable
    // host/vector copy, plus enable thread‑local minima.
    int global_min = std::numeric_limits<int>::max();

    #pragma omp parallel for reduction(min:global_min)
    for (std::size_t i = 0; i < x.size(); ++i) {
        const int val = x[i];
        // odd numbers are equivalent to val & 1 == 1
        if ((val & 1) && val < global_min)
            global_min = val;
    }

    return global_min;
}
