```cpp
#pragma once
#include <vector>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute y = alpha*A*x + beta*y
 * alpha and beta are scalars, x and y are length N and A is M x N.
 * A is in COO format (row, column, value).
 */
inline void spmv(double alpha,
                 std::vector<COOElement> const& A,
                 std::vector<double> const& x,
                 double beta,
                 std::vector<double> &y,
                 size_t M, size_t N)
{
    /* beta scaling – done in parallel */
    #pragma omp parallel for
    for (size_t i = 0; i < y.size(); ++i)
        y[i] *= beta;

    /* sparse matrix‑vector product – parallelized over non‑zeros.
     * Each thread updates distinct rows; concurrent writes to the same
     * row are protected with an atomic add.  For matrices with very few
     * duplicates per row, this costs almost nothing; otherwise, a
     * per‑thread buffer would be preferable. */
    #pragma omp parallel for
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const COOElement &e = A[idx];
        if (e.row < M && e.column < N) {
            double prod = alpha * e.value * x[e.column];
            #pragma omp atomic
            y[e.row] += prod;
        }
    }
}
