/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:

   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
void pixelCounts(const std::vector<int>& image, std::array<size_t, 256> &bins) {
    // Reset output buckets
    for (auto& v : bins) v = 0;

    // Number of threads we will use
    const int nthreads = omp_get_max_threads();

    // Per‑thread local histograms
    std::vector<std::array<size_t,256>> local(nthreads);
    for (int i = 0; i < nthreads; ++i)
        local[i].fill(0);

    // Parallel scan over image
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto &hist = local[tid];

        // Workload distribution
        #pragma omp for schedule(static)
        for (size_t i = 0; i < image.size(); ++i) {
            // Input values are guaranteed 0‑255; no bounds check needed
            hist[static_cast<unsigned char>(image[i])]++;
        }
    }

    // Combine local histograms into the final result
    for (int i = 0; i < 256; ++i)
        for (int t = 0; t < nthreads; ++t)
            bins[i] += local[t][i];
