#pragma once
#include <cstdint>
#include <vector>

/* Compute the prefix sum array of the vector x and return its sum.
   Example:
   input: [-7, 2, 1, 9, 4, 8]
   output: 15
*/
int64_t sumOfPrefixSum(const std::vector<int64_t>& x) {
    // Sum of prefix sums can be computed in a single pass:
    //   sum_{i=0}^{n-1} (n-i) * x[i]
    const std::size_t n = x.size();
    if (n == 0) return 0;

    int64_t result = 0;
    const std::int64_t multiplier_start = static_cast<std::int64_t>(n);
    std::int64_t multiplier = multiplier_start;

    // Use 128‑bit intermediate to avoid overflow for large inputs
    __int128 tmp = 0;

    for (std::size_t i = 0; i < n; ++i) {
        tmp += static_cast<__int128>(x[i]) * multiplier;
        --multiplier;
    }

    result = static_cast<int64_t>(tmp);
    return result;
}
