19_graph_shortest_path:
```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstddef>

/* Return the length of the shortest path from source to dest in the undirected graph defined
   by the adjacency matrix A. A is a row‑major NxN matrix. The graph is guaranteed to be
   connected and undirected. */
inline int shortestPathLength(const std::vector<int> &A, size_t N, int source, int dest)
{
    // Use the most compact representation for visited flags.
    std::vector<unsigned char> visited(N, 0);
    visited[source] = 1;

    // Use a flat queue of node indices. N elements are enough for any BFS.
    std::vector<int> q(N);
    size_t qhead = 0, qtail = 0;
    q[qtail++] = source;

    // Keep the current distance for each level by counting nodes at that level.
    int distance = 0;
    while (qhead < qtail) {
        size_t levelSize = qtail - qhead;          // nodes that are exactly 'distance' steps away
        for (size_t i = 0; i < levelSize; ++i) {
            int cur = q[qhead++];
            if (cur == dest)
                return distance;
            // Scan all neighbours of cur
            const int* row = &A[cur * N];
            for (int nxt = 0; nxt < static_cast<int>(N); ++nxt) {
                if (row[nxt] && !visited[nxt]) {
                    visited[nxt] = 1;
                    q[qtail++] = nxt;
                }
            }
        }
        ++distance;
    }
    return std::numeric_limits<int>::max();   // unreachable (should not happen for a connected graph)
}
