        for (auto& b : local) b = 0;

        // Compute stride for static scheduling
        #pragma omp for schedule(static)
        for (size_t i = 0; i < x.size(); ++i) {
            // Fast integer division by 10 using bit shift and masking
            // Safe because x[i] ∈ [0,100], so value < 1e2
            size_t bin = static_cast<size_t>(x[i]) / 10;
            ++local[bin];
