#pragma once
#include <vector>
#include <stack>
#include <algorithm>
#include <cstddef>
#include <cstdint>

/**
 * Compute the size of the largest connected component in an undirected graph
 * represented by an adjacency matrix `A` (row‑major).  The matrix is binary
 * (0/1).  The function preserves the original exact semantics: it returns the
 * maximum component size for a *single* call.  The implementation favours
 * speed on x86‑64 with GCC and OpenMP support, but it does *not* introduce
 * any data races or undefined behaviour.
 *
 * @param A  The adjacency matrix stored in row‑major order.
 * @param N  The number of vertices (matrix dimension).
 * @return   The size of the largest component.
 */
inline int largestComponent(const std::vector<int>& A, size_t N) noexcept
{
    // Use a narrow, fast visited marker.  One byte per node is enough.
    std::vector<uint8_t> visited(N, 0);
    int largest = 0;

    // Reuse a single stack for all components to avoid repeated allocation.
    std::vector<int> stk;
    stk.reserve(N);            // reserve once

    for (size_t start = 0; start < N; ++start) {
        if (visited[start]) continue;

        // New component: perform an explicit DFS.
        stk.clear();
        stk.push_back(static_cast<int>(start));
        visited[start] = 1;
        int compSize = 0;

        while (!stk.empty()) {
            int v = stk.back();
            stk.pop_back();
            ++compSize;

            // Access the row for vertex `v` directly.
            const int* row = A.data() + v * N;
            for (size_t j = 0; j < N; ++j) {
                if (row[j] == 1 && !visited[j]) {
                    visited[j] = 1;
                    stk.push_back(static_cast<int>(j));
                }
            }
        }

        if (compSize > largest) largest = compSize;
    }

    return largest;
}
