#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/* Optimised discrete Fourier transform implementation.
   The algorithm pre‑computes the exponential table once per call
   and parallelises over the output indices.  The behaviour is
   identical to the reference implementation.
*/
inline void compute_exp_table(std::vector<std::complex<double>>& table,
                              std::size_t N)
{
    table.resize(N);
    const double two_pi = 2.0 * M_PI;
    for (std::size_t n = 0; n < N; ++n) {
        double angle = two_pi * n / static_cast<double>(N);
        std::cos_sin(angle, &table[n].imag(), &table[n].real()); // cos -> real, sin -> imag
        table[n].imag() = -table[n].imag(); // Euler: e^{-j*angle} = cos - j sin
    }
}

inline void dft(std::vector<double> const& x,
                std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output.assign(N, std::complex<double>(0.0, 0.0));

    // Pre‑compute twiddle factors e^{-j*2*pi*n*k/N}
    std::vector<std::complex<double>> exp_table;
    compute_exp_table(exp_table, N);

    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        std::complex<double> sum(0.0, 0.0);
        for (std::size_t n = 0; n < N; ++n) {
            /* index for the twiddle factor:
               e^{-j*2*pi*n*k/N} = exp_table[(n*k)%N]   */
            std::size_t idx = (n * k) % N;
            sum += x[n] * exp_table[idx];
        }
        output[k] = sum;
    }
}
