 * thread‐local accumulators to avoid contention on `bins`.
 */
void firstLetterCounts(const std::vector<std::string>& s,
                       std::array<size_t, 26>& bins)
{
    // initialise output
    for (int i = 0; i < 26; ++i) bins[i] = 0;

    // number of available threads
    int nthreads = omp_get_max_threads();

    // per-thread local counters
    std::vector<std::array<size_t, 26>> local(nthreads);
    for (int t = 0; t < nthreads; ++t)
        for (int i = 0; i < 26; ++i) local[t][i] = 0;

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::array<size_t, 26>& cnt = local[tid];

        #pragma omp for schedule(static)
        for (size_t i = 0; i < s.size(); ++i) {
            // strings are guaranteed non‑empty and lowercase
            const char c = s[i][0];
            const int idx = c - 'a';
            cnt[idx] += 1;
        }
    }

    // reduce per‑thread results into final bins
    for (int t = 0; t < nthreads; ++t)
        for (int i = 0; i < 26; ++i)
            bins[i] += local[t][i];
}
