/// @brief  Compute the logical XOR (parity) of a `std::vector<bool>`.
/// @param  x  The input vector of bools.
/// @return  The XOR of all elements.
///
/// @code
///  // Example:
///  std::vector<bool> a {false, false, false, true};
///  bool r = reduceLogicalXOR(a);  // r == true
/// @endcode
inline bool reduceLogicalXOR(const std::vector<bool> &x) {
    // Use OpenMP to compute the parity in parallel.
    // The reduction operator `^` works on integer types, so we accumulate in a
    // single unsigned char and cast to bool at the end.
    unsigned char parity = 0;

    #pragma omp parallel for reduction(^:parity)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(x.size()); ++i) {
        parity ^= static_cast<unsigned char>(x[i]);
    }
    return static_cast<bool>(parity);
}
