struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Compute the matrix multiplication Y = A * X.
 * A: sparse MxK matrix in COO format.
 * X: sparse KxN matrix in COO format.
 * Y: dense MxN matrix in row‑major order, resized inside the function.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          size_t M,
          size_t K,
          size_t N)
{
    // Initialise Y to zero
    Y.assign(M * N, 0.0);

    /* Build a row‑wise hash for X: XbyRow[row] = list of elements in that row */
    std::vector<std::vector<COOElement>> XbyRow(K);
    for (const auto& x : X) {
        XbyRow[x.row].push_back(x);
    }

    /* Parallel traversal over A, updating Y atomically */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        const auto& a = A[i];
        const auto& vlist = XbyRow[a.column];   // X elements that match A's column

        const size_t aRowBase = a.row * N;
        const double aVal = a.value;

        for (const auto& x : vlist) {
            size_t idx = aRowBase + x.column;
#pragma omp atomic
            Y[idx] += aVal * x.value;
        }
    }
}
