};

inline double triangleArea(const Point& A, const Point& B, const Point& C) noexcept
{
    // Direct formula: 0.5*| (B-A)×(C-A) |
    const double dx1 = B.x - A.x, dy1 = B.y - A.y;
    const double dx2 = C.x - A.x, dy2 = C.y - A.y;
    return 0.5 * std::fabs(dx1 * dy2 - dy1 * dx2);
}

/* Return the area of the smallest triangle that can be formed by any 3 points. */
double smallestArea(std::vector<Point> const& points) noexcept
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Parallel outer loop with reduction (OpenMP 4.5+ supports parallel for reduction on double)
    #pragma omp parallel for schedule(static, 64) reduction(min:minArea)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n - 2); ++i) {
        const Point& A = points[i];
        for (std::size_t j = i + 1; j < n - 1; ++j) {
            const Point& B = points[j];
            for (std::size_t k = j + 1; k < n; ++k) {
                const double area = triangleArea(A, B, points[k]);
                if (area < minArea) minArea = area;
            }
        }
    }
    return minArea;
}
