45_sparse_la_sparse_solve:
```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/*
   Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   The function preserves the exact mathematical semantics of the original implementation.
*/
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double>& x,
                       size_t N)
{
   // Flatten the dense matrix (row-major) for cache-friendly access
   std::vector<double> mat(N * N, 0.0);
   std::vector<double> rhs = b;

   // Fill the matrix from COO representation
   for (const auto& e : A)
      mat[e.row * N + e.column] = e.value;

   x.assign(N, 0.0);

   // Gaussian elimination with partial pivoting.
   for (size_t i = 0; i < N; ++i) {
      // ----- Pivot search -----
      size_t maxRow = i;
      double maxVal = std::fabs(mat[i * N + i]);

      for (size_t k = i + 1; k < N; ++k) {
         double val = std::fabs(mat[k * N + i]);
         if (val > maxVal) {
            maxVal = val;
            maxRow = k;
         }
      }

      // If a zero pivot is encountered the system is singular; keep original behaviour
      if (maxRow != i) {
         // Row swap in matrix
         #pragma omp parallel for schedule(static)
         for (size_t j = 0; j < N; ++j) {
            std::swap(mat[i * N + j], mat[maxRow * N + j]);
         }
         // Swap RHS
         std::swap(rhs[i], rhs[maxRow]);
      }

      double pivot = mat[i * N + i];

      // ----- Eliminate below -----
      #pragma omp parallel for schedule(static)
      for (size_t k = i + 1; k < N; ++k) {
         double factor = -mat[k * N + i] / pivot;
         rhs[k] += factor * rhs[i];
         // Update remaining columns
         for (size_t j = i; j < N; ++j) {
            if (j == i)
               mat[k * N + j] = 0.0;
            else
               mat[k * N + j] += factor * mat[i * N + j];
         }
      }
   }

   // Back substitution
   for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
      x[i] = rhs[i] / mat[i * N + i];
      for (int k = i - 1; k >= 0; --k)
         rhs[k] -= mat[k * N + i] * x[i];
   }
}
