/* Compute one iteration of a 3‑point 1‑D Jacobi stencil on `input`. Store the results in `output`.
   Each element of `input` is averaged with its two neighbours and written into the corresponding
   element of `output`. Out‑of‑range indices are treated as 0.
   Example:
   input : [9, -6, -1, 2, 3]
   output: [1, 2/3, -5/3, 4/3, 5/3] */
inline void jacobi1D(const std::vector<double> &input, std::vector<double> &output) {
    const std::size_t n = input.size();
    if (n == 0) return;

    // Ensure output has the same size as input
    output.resize(n);

    // Handle boundaries separately (no branching inside the main loop)
    double first  = (n > 1 ? input[1] : 0.0) + input[0] + 0.0;   // i == 0
    double last   = (n > 1 ? input[n - 2] : 0.0) + 0.0 + input[n - 1]; // i == n-1

    // Main body – vectorised, parallelised
#pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        const double sum = input[i - 1] + input[i] + input[i + 1];
        output[i] = sum / 3.0;
    }

    // Write boundaries
    output[0] = first / 3.0;
    if (n > 1) output[n - 1] = last / 3.0;
}
