#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>

struct Point {
    double x, y;
};

inline double dist(const Point& a, const Point& b) noexcept {
    return std::hypot(b.x - a.x, b.y - a.y);
}

inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

inline bool point_less(const Point& a, const Point& b) noexcept {
    return (a.x < b.x) || (a.x == b.x && a.y < b.y);
}

double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3u) return 0.0;

    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(), point_less);

    std::vector<Point> hull(2 * n);
    std::size_t k = 0;

    // Lower hull
    for (const auto& p : pts) {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], p) <= 0.0) --k;
        hull[k++] = p;
    }

    // Upper hull
    for (std::size_t i = n - 1; i-- > 0;) {
        const Point& p = pts[i];
        while (k >= 2 + 1 && cross(hull[k - 2], hull[k - 1], p) <= 0.0) --k;
        hull[k++] = p;
    }

    hull.resize(k - 1);
    double per = 0.0;
    for (std::size_t i = 0; i + 1 < hull.size(); ++i) per += dist(hull[i], hull[i + 1]);
    per += dist(hull.back(), hull.front());
    return per;
}
