#include <set>

struct Point
{
    double x, y;
};

// Compute Euclidean distance between two points
inline double dist(const Point& a, const Point& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

// Return the distance between the closest two points in the vector points.
double closestPair(std::vector<Point> const& points)
{
    const std::size_t n = points.size();
    if (n < 2) return 0.0;

    // Sort points by x-coordinate (and y as tiebreaker)
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // Active set sorted by y-coordinate
    struct ByY
    {
        bool operator()(Point const& a, Point const& b) const
        {
            return (a.y < b.y) || (a.y == b.y && a.x < b.x);
        }
    };
    std::set<Point, ByY> active;
    double best = std::numeric_limits<double>::infinity();
    std::size_t left = 0;

    for (const Point& p : sorted)
    {
        // Remove points that are farther than best in x-direction
        while (p.x - sorted[left].x > best)
        {
            active.erase(sorted[left]);
            ++left;
        }

        // Define search bounds in y-direction
        Point lower{ -std::numeric_limits<double>::infinity(), p.y - best };
        Point upper{  std::numeric_limits<double>::infinity(), p.y + best };
        auto itLow = active.lower_bound(lower);
        auto itHigh = active.upper_bound(upper);

        // Check only points within the rectangle
        for (auto it = itLow; it != itHigh; ++it)
        {
            double d = dist(p, *it);
            if (d < best)
                best = d;
        }

        active.insert(p);
    }

    return best;
}
