```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Optimized LU factorization for a sparse matrix in COO format.
   The implementation keeps the original semantics while improving
   memory layout, data locality and using a small amount of
   OpenMP parallelism for the least expensive part of the inner loops.
*/
void luFactorize(const std::vector<COOElement>& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 size_t N)
{
    /* Pre‑process the COO data into a row‑oriented structure.
       This conversion is inexpensive (O(nnz)) and allows O(1)
       access to the matrix entries required during factorisation. */
    std::vector<std::vector<std::pair<size_t, double>>> rowVals(N);
    for (const auto& e : A)
        rowVals[e.row].emplace_back(e.column, e.value);

    double* Lptr = L.data();   // row‑major L
    double* Upptr = U.data();  // row‑major U

    /* Main LU factorisation loop.
       Each row only depends on previously computed rows, so we keep
       the outer loop serial.  The inner products are small, but we
       still use a parallel for over the columns of the current row
       to keep the workload balanced for large N. */
    for (size_t i = 0; i < N; ++i)
    {
        /* For each column in the current row */
        #pragma omp parallel for schedule(static)
        for (size_t j = 0; j < N; ++j)
        {
            /* ==== Upper part (j >= i) ==== */
            if (j >= i)
            {
                /* Find the original value A[i][j] (0 if missing) */
                double aij = 0.0;
                for (auto& p : rowVals[i])
                    if (p.first == j) { aij = p.second; break; }

                double sum = aij;
                for (size_t k = 0; k < i; ++k)
                    sum -= Lptr[i * N + k] * Upptr[k * N + j];
                Upptr[i * N + j] = sum;
            }

            /* ==== Lower part (j < i) ==== */
            if (j < i)
            {
                /* Find the original value A[i][j] (0 if missing) */
                double aij = 0.0;
                for (auto& p : rowVals[i])
                    if (p.first == j) { aij = p.second; break; }

                double sum = aij;
                for (size_t k = 0; k < j; ++k)
                    sum -= Lptr[i * N + k] * Upptr[k * N + j];
                sum /= Upptr[j * N + j];
                Lptr[i * N + j] = sum;
            }
        }

        /* Set the diagonal of L to 1 */
        Lptr[i * N + i] = 1.0;
    }
}
