/*  Set every cell's value to 1 if it has exactly one neighbor that's a 1.
    Otherwise set it to 0.
    Neighbors are the 4 orthogonal cells (up, down, left, right).
    Input and output are NxN grids stored in row‑major order.
*/
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int>& output,
                     std::size_t N)
{
    // Work directly on raw pointers to avoid bounds checking.
    const int16_t*  in  = reinterpret_cast<const int16_t*>(input.data());   // assume values are 0 or 1
    int16_t*        out = reinterpret_cast<int16_t*>(output.data());
    const std::size_t stride = N;

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t idx = i * stride;
        const std::size_t im1 = (i > 0)   ? (idx - stride) : SIZE_MAX; // index of cell above
        const std::size_t ip1 = (i < N-1) ? (idx + stride) : SIZE_MAX; // index of cell below

        for (std::size_t j = 0; j < N; ++j) {
            std::size_t ij = idx + j;
            std::size_t left  = (j > 0)   ? (ij - 1) : SIZE_MAX;
            std::size_t right = (j < N-1) ? (ij + 1) : SIZE_MAX;

            unsigned char count = 0;
            if (im1 != SIZE_MAX && in[im1] == 1) ++count;
            if (ip1 != SIZE_MAX && in[ip1] == 1) ++count;
            if (left  != SIZE_MAX && in[left]  == 1) ++count;
            if (right != SIZE_MAX && in[right] == 1) ++count;

            out[ij] = (count == 1) ? 1 : 0;
        }
    }
}
