   [0, 0.25), [0.25, 0.5), [0.5, 0.75), and [0.75, 1).
   The counts are stored in the `bins` array. */
void countQuartiles(std::vector<double> const& x, std::array<std::size_t, 4> &bins)
{
    // Initialise output bins to zero.
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    const std::size_t n = x.size();
    if (n == 0)
        return;

    // Parallel processing with thread‐local counters to avoid atomics inside the loop.
    #pragma omp parallel
    {
        std::array<std::size_t, 4> local_bins{0, 0, 0, 0};

        #pragma omp for
        for (std::size_t i = 0; i < n; ++i) {
            const double val   = x[i];
            const double frac  = val - static_cast<double>(static_cast<int>(val));

            if (frac < 0.25)         ++local_bins[0];
            else if (frac < 0.5)     ++local_bins[1];
            else if (frac < 0.75)    ++local_bins[2];
            else                     ++local_bins[3];
        }

        // Merge thread‑local counts into the global array.
        #pragma omp atomic
        bins[0] += local_bins[0];
        #pragma omp atomic
        bins[1] += local_bins[1];
        #pragma omp atomic
        bins[2] += local_bins[2];
        #pragma omp atomic
        bins[3] += local_bins[3];
    }
}
