struct Point {
    double x, y;
};

/* Compute the convex hull of a set of points.
   The returned hull contains the vertices of the smallest convex polygon
   that encloses all input points, in counter‑clockwise order (starting with
   the left‑most point). */
inline void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();
    if (n < 3) {                     // trivial case
        hull = points;
        return;
    }

    /* ---------- 1. Sort points by (x,y)  ----------
       std::sort is usually faster than a hand‑written
       parallel sort for small to medium input sizes     */
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    /* ---------- 2. Build hull with monotone chain ----------
       - reserve space for the worst case (2*n points)
       - use a raw array for the stack to avoid virtual
         function dispatch and bounds checking overhead */
    std::vector<Point> stack;
    stack.reserve(2 * n);

    // cross product helper (vector AP x vector AB)
    auto cross = [](const Point& A, const Point& B, const Point& C) noexcept -> double {
        return (B.x - A.x) * (C.y - A.y) - (B.y - A.y) * (C.x - A.x);
    };

    // lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (stack.size() >= 2 &&
               cross(stack[stack.size() - 2], stack[stack.size() - 1], sorted[i]) <= 0.0)
            stack.pop_back();
        stack.push_back(sorted[i]);
    }

    // upper hull (skip first and last point of sorted array!)
    for (std::size_t i = n - 1; i > 0; --i) {          // i == 0 terminates loop
        while (stack.size() > n &&                                 // > n because lower hull
               cross(stack[stack.size() - 2], stack[stack.size() - 1], sorted[i - 1]) <= 0.0)
            stack.pop_back();
        stack.push_back(sorted[i - 1]);
    }

    /* remove the last point, which is the same as the first one */
    stack.pop_back();

    hull.swap(stack);        // move result to output parameter
}
