inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output) {
    const std::size_t N = x.size();
    output.resize(N);

    if (N == 0) return;

    constexpr int NUM_THREADS = 8;
    const std::size_t chunk = (N + NUM_THREADS - 1) / NUM_THREADS;

    std::vector<int64_t> localSums(NUM_THREADS, 0);

    /* First pass: compute partial sums locally */
    #pragma omp parallel num_threads(NUM_THREADS)
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * chunk;
        if (start >= N) return;
        const std::size_t end   = std::min(start + chunk, N);

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum       += x[i];
            output[i]  = sum;          // local prefix sum
        }
        localSums[tid] = sum;
    }

    /* Prefix sum over the chunk totals */
    int64_t offset = 0;
    for (int i = 0; i < NUM_THREADS; ++i) {
        const int64_t s = localSums[i];
        localSums[i] = offset;
        offset += s;
    }

    /* Second pass: add the offset of the previous chunks */
    #pragma omp parallel num_threads(NUM_THREADS)
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * chunk;
        if (start >= N) return;
        const std::size_t end   = std::min(start + chunk, N);
        const int64_t off = localSums[tid];

        for (std::size_t i = start; i < end; ++i) {
            output[i] += off;
        }
    }
}
