/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
 */
size_t findClosestToPi(std::vector<double> const& x) {
    const size_t n = x.size();
    if (n == 0) return 0; // undefined, but keeps behavior

    size_t bestIdx = 0;
    double bestDiff = std::abs(x[0] - M_PI);

    #pragma omp parallel
    {
        size_t localIdx = bestIdx;
        double localDiff = bestDiff;

        #pragma omp for nowait schedule(static)
        for (size_t i = 1; i < n; ++i) {
            const double d = std::abs(x[i] - M_PI);
            if (d < localDiff) {
                localDiff = d;
                localIdx  = i;
            }
        }

        #pragma omp critical
        {
            if (localDiff < bestDiff) {
                bestDiff = localDiff;
                bestIdx  = localIdx;
            }
        }
    }

    return bestIdx;
}
