/*
   In‑place iterative Cooley‑Tukey radix‑2 FFT.
   The result is written to the supplied real and imaginary vectors `r` and `i`.
   The input vector `x` is NOT modified.
*/
void fft(const std::vector<std::complex<double>>& x,
         std::vector<double>& r,
         std::vector<double>& i) {
    const std::size_t N = x.size();

    // Ensure the output buffers are correctly sized
    r.resize(N);
    i.resize(N);

    // Working copies: separate real and imaginary parts
    std::vector<double> re(N), im(N);
    for (std::size_t idx = 0; idx < N; ++idx) {
        re[idx] = std::real(x[idx]);
        im[idx] = std::imag(x[idx]);
    }

    /* -------------------------------------------------------------
       Pre‑compute bit‑reversed indices
    ------------------------------------------------------------- */
    const std::size_t log2N = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t revIdx = 0;
        std::size_t tmp = i;
        for (std::size_t j = 0; j < log2N; ++j) {
            revIdx = (revIdx << 1) | (tmp & 1);
            tmp >>= 1;
        }
        rev[i] = revIdx;
    }

    /* -------------------------------------------------------------
       Bit‑reversal permutation
    ------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i) {
            std::swap(re[i], re[j]);
            std::swap(im[i], im[j]);
        }
    }

    /* -------------------------------------------------------------
       Pre‑compute twiddle factors for all stages
    ------------------------------------------------------------- */
    std::vector<std::complex<double>> twiddles(N / 2);
    const double twoPi = 2.0 * M_PI;
    for (std::size_t k = 0; k < N / 2; ++k) {
        double ang = -twoPi * static_cast<double>(k) / static_cast<double>(N);
        twiddles[k] = std::complex<double>(std::cos(ang), std::sin(ang));
    }

    /* -------------------------------------------------------------
       Butterfly stages
    ------------------------------------------------------------- */
    std::size_t n = 1;
    while (n < N) {
        const std::size_t step = n << 1;
        // The stride between butterfly numbers
        const std::size_t stride = N / step;

        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            std::complex<double> w = twiddles[i * stride];
            for (std::size_t j = i; j < N; j += step) {
                std::size_t k = j + n;
                const double tempr =  re[j] - re[k];
                const double tempi =  im[j] - im[k];
                const double wr = w.real(), wi = w.imag();

                re[j] += re[k];
                im[j] += im[k];
                re[k] =  re[j] + (wr * tempr - wi * tempi);
                im[k] =  im[j] + (wi * tempr + wr * tempi);
            }
        }
        n = step;
    }

    /* -------------------------------------------------------------
       Copy back to output vectors
    ------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (std::size_t idx = 0; idx < N; ++idx) {
        r[idx] = re[idx];
        i[idx] = im[idx];
    }
}
