#include <omp.h>

inline std::complex<double> fftw_twiddle(double theta)
{
    return std::complex<double>(std::cos(theta), -std::sin(theta));
}

//----- bit reversal table ----------------------------------------------------
static inline uint32_t reverse_bits(uint32_t x, unsigned int log_n)
{
    // Uses 32‑bit reverse and truncate to log_n bits
    x = ((x & 0x55555555u) << 1) | ((x & 0xaaaaaaaau) >> 1);
    x = ((x & 0x33333333u) << 2) | ((x & 0xccccccccu) >> 2);
    x = ((x & 0x0f0f0f0fu) << 4) | ((x & 0xf0f0f0f0u) >> 4);
    x = ((x & 0x00ff00ffu) << 8) | ((x & 0xff00ff00u) >> 8);
    x = (x >> 16) | (x << 16);
    return x >> (32 - log_n);
}

//----- main FFT implementation -----------------------------------------------
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    const unsigned int logN = static_cast<unsigned int>(std::log2(N));
    const double theta0 = M_PI / static_cast<double>(N);
    std::complex<double> twiddle = fftw_twiddle(theta0);
    std::complex<double> w = 1.0;

    // Iterative decimation‑in‑frequency radix‑2 FFT
    std::size_t step = 1;
    for (unsigned int stage = 0; stage < logN; ++stage) {
        unsigned int halfStep = step;
        step <<= 1;
        const std::complex<double> w_mult = twiddle * twiddle;
        w = 1.0;

        // Parallel over the outer butterfly blocks
#pragma omp parallel for schedule(static)
        for (std::size_t start = 0; start < N; start += step) {
            for (std::size_t j = 0; j < halfStep; ++j) {
                std::size_t i = start + j;
                std::size_t k = i + halfStep;
                std::complex<double> t = x[i] - x[k];
                x[i] += x[k];
                x[k] = t * w;
            }
        }
        w *= w_mult;
    }

    // Bit reversal (in‑place)
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = reverse_bits(static_cast<uint32_t>(i), logN);
        if (j > i) std::swap(x[i], x[j]);
    }

    // Conjugate the result
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) x[i] = std::conj(x[i]);
}
