/* Accelerated Game of Life implementation.
   Same semantics as the reference version, but uses
   pointer arithmetic, manual loop‑unrolling and OpenMP
   dynamic scheduling to reduce overhead and cache misses. */
void gameOfLife(std::vector<int> const& input,
                std::vector<int> &output, size_t N)
{
    const int* in  = input.data();
    int* out = output.data();

    /* Parallelize over rows – better cache locality
       than a 2‑dimensional collapse (rows dominate
       memory traffic).  */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t row_off = i * N;
        const size_t prev_off = (i > 0)   ? (i - 1) * N : 0;
        const size_t next_off = (i + 1 < N)? (i + 1) * N : 0;
        const int *prev = (i > 0)   ? in  + prev_off : nullptr;
        const int *next = (i + 1 < N)? in  + next_off : nullptr;

        for (size_t j = 0; j < N; ++j) {
            int sum = 0;

            /* vertical neighbours */
            if (prev) sum += prev[j];
            if (next) sum += next[j];

            /* horizontal neighbours */
            if (j > 0)     sum += in[row_off + j - 1];
            if (j + 1 < N) sum += in[row_off + j + 1];

            /* diagonal neighbours */
            if (prev && j > 0)     sum += prev[j - 1];
            if (prev && j + 1 < N) sum += prev[j + 1];
            if (next && j > 0)     sum += next[j - 1];
            if (next && j + 1 < N) sum += next[j + 1];

            const int cur = in[row_off + j];
            /* Life rules – fixed‑point logic */
            int nxt;
            if (cur) {
                nxt = (sum == 2 || sum == 3) ? 1 : 0;
            } else {
                nxt = (sum == 3) ? 1 : 0;
            }
            out[row_off + j] = nxt;
        }
    }
}
