/* Multiply matrix A (MxN, row‑major) by vector x (size N) and store
   result in vector y (size M).  The routine is fully parallelized
   with OpenMP and uses blocking for better cache locality.  It
   preserves the exact numerical result of the reference implementation. */
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 size_t M,
                 size_t N)
{
    /* Block size tuned empirically for typical cache sizes on modern
       x86‑64 systems (64‑byte cache line, 16‑N cache lines).  Block
       size of 64 rows gives about 1 KB of data per block (A rows),
       which fits comfortably in L1 cache and has minimal impact on
       L2/L3 throughput. */
    constexpr size_t BLOCK_ROWS = 64;

    #pragma omp parallel for schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += BLOCK_ROWS)
    {
        size_t i_max = std::min(i0 + BLOCK_ROWS, M);
        for (size_t i = i0; i < i_max; ++i)
        {
            double sum = 0.0;
            /* Inner loop unrolled by 8 for better ILP and fewer branch
               mispredictions.  The compiler will keep the unroll
               as long as it is safe: current GCC -O2 will auto‑unroll
               similar loops, but we force it for clarity. */
            size_t j = 0;
            for (; j + 7 < N; j += 8)
            {
                sum += A[i * N + j]   * x[j];
                sum += A[i * N + j+1] * x[j+1];
                sum += A[i * N + j+2] * x[j+2];
                sum += A[i * N + j+3] * x[j+3];
                sum += A[i * N + j+4] * x[j+4];
                sum += A[i * N + j+5] * x[j+5];
                sum += A[i * N + j+6] * x[j+6];
                sum += A[i * N + j+7] * x[j+7];
            }
            /* Tail handling */
            for (; j < N; ++j)
                sum += A[i * N + j] * x[j];

            y[i] = sum;
        }
    }
