// Sorts a vector in place, ignoring all zero elements.
// The relative order of zeros is preserved, and the zeros stay in place.
// Non‑zero values are sorted ascendingly.

// This implementation uses a two‑step approach:
//  1. Collect all indices of non‑zero elements.
//  2. Extract the values, sort them, and write them back.
// The algorithm runs in O(n log n) time with only a few additional
// memory allocations.  The code is thread‑parallel capable if the
// input size is large enough to benefit from OpenMP, but the
// computations are serial in the critical parts (sorting and
// writing back).  GCC 9+ with -O2 will auto‑vectorize the
// inner loops efficiently.

inline void sortIgnoreZero(std::vector<int>& x)
{
    const std::size_t n = x.size();
    if (n <= 1) return;

    std::vector<int> indices;
    indices.reserve(n);

    // Collect indices of non‑zero elements
    for (std::size_t i = 0; i < n; ++i)
        if (x[i] != 0)
            indices.push_back(static_cast<int>(i));

    if (indices.empty()) return;

    std::vector<int> values;
    values.reserve(indices.size());

    // Extract values
    for (int idx : indices)
        values.push_back(x[idx]);

    // Sort the values
    std::sort(values.begin(), values.end());

    // Write back sorted values to their original positions
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < indices.size(); ++i)
        x[indices[i]] = values[i];
}
