    inline void merge_inplace(std::vector<Result> &a, size_t left, size_t mid, size_t right) noexcept {
        std::vector<Result> tmp;
        tmp.reserve(right - left);
        size_t i = left, j = mid;
        while (i < mid && j < right) {
            if (a[i].startTime <= a[j].startTime) {
                tmp.push_back(std::move(a[i]));
                ++i;
            } else {
                tmp.push_back(std::move(a[j]));
                ++j;
