    inline void parallel_sort(std::vector<Result> &a, size_t left, size_t right, size_t threshold) noexcept {
        if (right - left <= threshold) {
            std::sort(a.begin() + left, a.begin() + right, [](const Result &x, const Result &y) {
                return x.startTime < y.startTime;
            });
            return;
        }
        size_t mid = left + (right - left) / 2;
        #pragma omp task shared(a) if (right - left > threshold * 2)
        parallel_sort(a, left, mid, threshold);
        #pragma omp task shared(a) if (right - left > threshold * 2)
        parallel_sort(a, mid, right, threshold);
        #pragma omp taskwait
        merge_inplace(a, left, mid, right);
    }
}

inline void sortByStartTime(std::vector<Result> &results) {
    if (results.empty()) return;
    const size_t threshold = 1 << 12;          // 4096 elements → serial sort
    #pragma omp parallel
    {
        #pragma omp single
        detail::parallel_sort(results, 0, results.size(), threshold);
    }
}
