#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major order.  
   x and b are length N. The algorithm uses partial pivoting
   and is identical to the reference implementation.  */
void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // Work on local copies – required to preserve the input
    std::vector<double> a(A);
    std::vector<double> rhs(b);

    const size_t stride = N;

    /* Forward elimination (Gaussian elimination with partial pivoting) */
    for (size_t k = 0; k < N - 1; ++k) {
        // Find pivot row
        size_t max_row = k;
        double max_val = std::abs(a[k*stride + k]);
        for (size_t i = k + 1; i < N; ++i) {
            double val = std::abs(a[i*stride + k]);
            if (val > max_val) { max_val = val; max_row = i; }
        }
        // If pivot is zero, system is singular – abort
        if (max_val == 0.0) return;

        // Swap rows if needed
        if (max_row != k) {
            for (size_t col = k; col < N; ++col)
                std::swap(a[k*stride + col], a[max_row*stride + col]);
            std::swap(rhs[k], rhs[max_row]);
        }

        double pivot = a[k*stride + k];

        /* Eliminate below pivot – parallel over rows */
        #pragma omp parallel for schedule(static)
        for (size_t i = k + 1; i < N; ++i) {
            double factor = a[i*stride + k] / pivot;
            a[i*stride + k] = 0.0;               // explicit zero for clarity
            for (size_t j = k + 1; j < N; ++j)
                a[i*stride + j] -= factor * a[k*stride + j];
            rhs[i] -= factor * rhs[k];
        }
    }

    /* Back substitution */
    for (int i = int(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j)
            sum += a[i*stride + j] * x[j];
        x[i] = (rhs[i] - sum) / a[i*stride + i];
    }
}
