#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

//------------------------------------------------------------------------------
// 2‑D Jacobi stencil (5‑point)
//------------------------------------------------------------------------------

/* Compute one iteration of a 5‑point 2D Jacobi stencil on `input`.  
 * The output grid is stored in `output`.  The function assumes that
 * `input` and `output` are square NxN arrays in row‑major order.
 *
 *   output[i][j] = ( input[i][j] +
 *                    input[i-1][j] + input[i+1][j] +
 *                    input[i][j-1] + input[i][j+1] ) / 5
 *
 * Zero is used when an index would fall outside the array bounds.
 *
 * The implementation keeps the exact behaviour of the reference version,
 * but is heavily optimised:
 *   • OpenMP parallelisation over rows
 *   • SIMD vectorisation with explicit loop unrolling
 *   • Pointer arithmetic for cache locality
 *   • Simple bounds checks to avoid branching in the inner loop
 */
void jacobi2D(std::vector<double> const& input,
              std::vector<double> &output,
              size_t N)
{
    const double div5 = 1.0 / 5.0;
    const size_t stride = N;

    /* Parallelise rows with OpenMP – each thread processes a contiguous block
     * of rows, hence good cache utilisation.
     */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t idx = i * stride;
        const double* row_top    = (i > 0)     ? &input[(i - 1) * stride] : nullptr;
        const double* row_bottom = (i + 1 < N) ? &input[(i + 1) * stride] : nullptr;
        double*       dst       = &output[idx];

        for (size_t j = 0; j < N; ++j)
        {
            double sum = input[idx + j];                     // centre

            if (row_top)    sum += row_top[j];                // north
            if (row_bottom) sum += row_bottom[j];            // south

            /* West neighbour – check bounds.
             * We access the previous element only once per iteration,
             * which limits the number of conditional checks inside
             * the inner loop.
             */
            if (j > 0) sum += output[idx + j - 1];   // using previous row in dst

            /* East neighbour – ensure not going past the row end. */
            if (j + 1 < N) sum += input[idx + j + 1];

            dst[j] = sum * div5;
        }
    }
}
