#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Dense matrix–matrix multiplication: C += A * B
   A is M×K, B is K×N, C is M×N, all stored row‑major.
   The routine is fully tiled and parallelised with OpenMP.
   It preserves exact IEEE‑754 semantics (no `-ffast-math`). */
inline void gemm(const std::vector<double>& A,
                 const std::vector<double>& B,
                 std::vector<double>& C,
                 std::size_t M, std::size_t K, std::size_t N) {
    // Tile dimensions – tuned for a typical L1 cache of ~32 KB per core
    constexpr std::size_t BM = 32;   // block size for rows of A / C
    constexpr std::size_t BN = 32;   // block size for columns of B / C
    constexpr std::size_t BK = 32;   // block size for inner dimension

    // Ensure C is zero‑initialised before accumulation
    // (caller may rely on previous contents – handled externally)

    // Parallelise over outermost block of rows of A / C
    #pragma omp parallel for schedule(static, 1)
    for (std::size_t ii = 0; ii < M; ii += BM) {
        std::size_t i_max = std::min(ii + BM, M);
        for (std::size_t kk = 0; kk < K; kk += BK) {
            std::size_t k_max = std::min(kk + BK, K);
            for (std::size_t jj = 0; jj < N; jj += BN) {
                std::size_t j_max = std::min(jj + BN, N);

                // Compute tile C[ii: i_max, jj: j_max] += A[ii: i_max, kk: k_max] *
                //                                    B[kk: k_max, jj: j_max]
                for (std::size_t i = ii; i < i_max; ++i) {
                    double* c_ptr = &C[i * N + jj];
                    const double* b_row_ptr = &B[kk * N + jj];
                    const double* a_row_ptr = &A[i * K + kk];
                    for (std::size_t k = kk; k < k_max; ++k, ++a_row_ptr) {
                        double aik = *a_row_ptr;
                        const double* b_ptr = b_row_ptr;
                        double* c = c_ptr;
                        for (std::size_t j = jj; j < j_max; ++j, ++b_ptr, ++c) {
                            *c += aik * (*b_ptr);
                        }
                    }
                }
            }
        }
    }
}
