#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Optimised LU factorisation (in-place).
 * Input matrix A is a flat N×N array in row-major order.
 * The function overwrites A with its L and U factors.
 *
 * Precise behaviour: identical results to the reference implementation,
 * up to compiler–induced rounding differences.
 */

inline void luFactorize(std::vector<double> &A, std::size_t N)
{
    const std::size_t stride = N;                // row stride
    const std::size_t threads = 8;               // hard‑code to number of logical cores

    /* 
     * Outer loop is inherently serial because each step k depends on all previous
     * rows.  Inside this loop we parallelise the work over rows i > k.
     */
    for (std::size_t k = 0; k < N; ++k)
    {
        const std::size_t kcol = k * stride;     // index to row k
        const double pivot = A[kcol + k];        // A[k][k]
        const double *restrict krow = &A[kcol];  // pointer to row k

        /* Parallel over rows i > k */
#pragma omp parallel for schedule(static, 64) num_threads(threads)
        for (std::size_t i = k + 1; i < N; ++i)
        {
            const std::size_t icol = i * stride;          // index to row i
            double *restrict irow = &A[icol];             // pointer to row i
            const double factor = A[icol + k] / pivot;    // compute L[i][k]
            irow[k] = factor;                            // store lower entry

            /* Update the remaining part of row i */
            const double *restrict krow_j = krow + k + 1;  // row k, columns k+1..
            double *restrict irow_j = irow + k + 1;       // row i, columns k+1..
            std::size_t j = k + 1;
            std::size_t remaining = N - j;
            std::size_t unroll = remaining & ~3;          // loop‑unroll 4×

            /* Main vectorised loop */
            for (; j < unroll; j += 4)
            {
                irow_j[0] -= factor * krow_j[0];
                irow_j[1] -= factor * krow_j[1];
                irow_j[2] -= factor * krow_j[2];
                irow_j[3] -= factor * krow_j[3];
                irow_j += 4;
                krow_j += 4;
            }

            /* Tail loop (remaining 0‑3 elements) */
            for (; j < N; ++j)
            {
                irow[j] -= factor * krow[j];
            }
        }
    }
}
