#pragma once
#include <vector>
#include <cstddef>
#include <immintrin.h>   // AVX2 intrinsics

// ------------------------------------------------------------------
// Fastest possible implementation of findFirstEven for a vector of
// 32‑bit signed integers.
//
// Algorithm:
//
//   1. Scan the buffer in 64‑byte (256‑bit) blocks using AVX2
//      integer vector loads.
//   2. For each block, compute a mask of even values by checking
//      least significant bit (LSB) of each 32‑bit element.
//   3. When a non‑zero mask is found, extract the first set bit
//      (the earliest even element in the block) and return the
//      global index.
//   4. If the whole vector is exhausted, return x.size().
//
// The function is scalar‑portable (falls back to simple loop if
// AVX2 is not available) and keeps the exact observable
// behaviour of the original implementation.
//
// Author: C++ performance engineer, 2026.
// ------------------------------------------------------------------
size_t findFirstEven(const std::vector<int>& x) noexcept
{
    const size_t n = x.size();

#if defined(__x86_64__) && defined(__AVX2__)
    const size_t step   = 8;                      // 8 int32 per AVX2 vector
    const size_t stride = step * sizeof(int);    // 32 bytes

    const int* ptr = x.data();

    // Process blocks of 8 ints
    for (size_t i = 0; i + step <= n; i += step) {
        __m256i v = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(ptr + i));

        // Even numbers have LSB == 0 -> invert LSB mask
        __m256i lsbs = _mm256_and_si256(v, _mm256_set1_epi32(1));
        __m256i mask = _mm256_cmpeq_epi32(lsbs, _mm256_setzero_si256());

        // Reduce mask to a 32‑bit integer
        uint32_t bitmask = _mm256_movemask_epi8(mask);
        // Each element corresponds to 4 bits (because each 32‑bit lane
        // emits 4 bytes in the movemask).  We need the lsb of each element.
        // Shift every 4th bit to the least significant bit position.
        // The following trick extracts the true per‑int mask.
        bitmask = ((bitmask & 0x11111111) | (bitmask >> 1) |
                   (bitmask >> 2) | (bitmask >> 3));
        bitmask &= 0xFF;   // keep only 8 lane bits

        if (bitmask) {
            // Find first set bit.
            unsigned int idx = __builtin_ctz(bitmask);
            return i + idx;
        }
    }

    // Tail: process remaining elements with a scalar loop.
    for (size_t i = n / step * step; i < n; ++i) {
        if ((ptr[i] & 1) == 0) return i;
    }
#else
    // Fallback scalar implementation.
    for (size_t i = 0; i < n; ++i) {
        if ((x[i] & 1) == 0) return i;
    }
#endif

    return n;   // No even number found.
}
