#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

// Edge detection kernel (3x3)
static constexpr int edgeKernel[3][3] = {
    { -1, -1, -1 },
    { -1,  8, -1 },
    { -1, -1, -1 }
};

/* Convolve the edge kernel with a grayscale image.
 *
 * imageIn   : input image (row‑major, size N×N)
 * imageOut  : output image (row‑major, size N×N)
 * N         : image dimension
 *
 * Behaviour is identical to the reference implementation:
 *   * Zero padding outside the image
 *   * Result clipped to [0, 255]
 */
inline void convolveKernel(const std::vector<int>& imageIn,
                           std::vector<int>& imageOut,
                           std::size_t N)
{
    if (imageOut.size() < N * N)
        imageOut.resize(N * N);

    const int*  in  = imageIn.data();
    int*        out = imageOut.data();

    /* --- Parallelisation -------------------------------------------------- */
    /*  The outer two loops are embarrassingly parallel.  Using a static
     *  schedule lets each thread work on a contiguous block of rows, which
     *  yields good cache behaviour even with the cheap per‑pixel work.
     */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        /* --- Handle border rows ------------------------------------------ */
        if (i == 0 || i == N - 1) {
            for (std::size_t j = 0; j < N; ++j) {
                int sum = 0;
                for (int k = -1; k <= 1; ++k) {
                    std::size_t x = i + k;
                    if (x >= N) continue;
                    for (int l = -1; l <= 1; ++l) {
                        std::size_t y = j + l;
                        if (y >= N) continue;
                        sum += in[x * N + y] * edgeKernel[k + 1][l + 1];
                    }
                }
                out[i * N + j] = static_cast<int>(std::clamp(sum, 0, 255));
            }
            continue;
        }

        /* --- Handle interior rows (no bounds checks) --------------------- */
        for (std::size_t j = 0; j < N; ++j) {
            /* Special case for left/right edges of the row */
            if (j == 0 || j == N - 1) {
                int sum = 0;
                for (int k = -1; k <= 1; ++k) {
                    std::size_t x = i + k;
                    for (int l = -1; l <= 1; ++l) {
                        std::size_t y = j + l;
                        if (y >= N) continue;
                        sum += in[x * N + y] * edgeKernel[k + 1][l + 1];
                    }
                }
                out[i * N + j] = static_cast<int>(std::clamp(sum, 0, 255));
                continue;
            }

            /* Two‑pixel unrolled inner loop for the central part */
            int sum1 = 0, sum2 = 0;
            for (int k = -1; k <= 1; ++k) {
                std::size_t x = i + k;
                std::size_t idx = x * N;
                sum1 += in[idx +     j - 1] * edgeKernel[k + 1][0];
                sum1 += in[idx +     j    ] * edgeKernel[k + 1][1];
                sum1 += in[idx +     j + 1] * edgeKernel[k + 1][2];
                sum2 += in[idx +     j + 2] * edgeKernel[k + 1][0];
                sum2 += in[idx +     j + 3] * edgeKernel[k + 1][1];
                sum2 += in[idx +     j + 4] * edgeKernel[k + 1][2];
            }
            /* Store results (clipped) */
            out[i * N + j]     = static_cast<int>(std::clamp(sum1, 0, 255));
            out[i * N + j + 1] = static_cast<int>(std::clamp(sum2, 0, 255));
        }
    }
}
